import{_ as i,o,c as n,a1 as a}from"./chunks/framework.BwbI10pK.js";const g=JSON.parse('{"title":"Performance Engineering","description":"","frontmatter":{},"headers":[],"relativePath":"en/performance/index.md","filePath":"en/performance/index.md"}'),t={name:"en/performance/index.md"};function r(l,e,s,c,d,p){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="performance-engineering" tabindex="-1">Performance Engineering <a class="header-anchor" href="#performance-engineering" aria-label="Permalink to &quot;Performance Engineering&quot;">​</a></h1><blockquote><p>Subtitle: Around the critical path and rendering pipeline, locate performance problems to specific stages.</p></blockquote><h2 id="module-positioning" tabindex="-1">Module Positioning <a class="header-anchor" href="#module-positioning" aria-label="Permalink to &quot;Module Positioning&quot;">​</a></h2><p>Performance optimization is not a single-point trick like &quot;add will-change&quot; or &quot;use transform for animations.&quot; It is a complete engineering method from problem localization to optimization verification. This module centers on the modern browser&#39;s critical path and rendering pipeline, decomposing performance issues into three models — waiting, blocking, and redundant work — so that every optimization is evidence-based.</p><p>Each optimization recommendation is accompanied by a DevTools verification path and an actionable practice checklist, avoiding pseudo-optimizations that &quot;look improved&quot; but actually change nothing.</p><h2 id="core-topics" tabindex="-1">Core Topics <a class="header-anchor" href="#core-topics" aria-label="Permalink to &quot;Core Topics&quot;">​</a></h2><ul><li><strong>Critical path</strong>: TTFB / resource discovery / HTML-CSS-JS parsing / module dependency graph / LCP breakdown.</li><li><strong>Rendering pipeline</strong>: Cost and triggering conditions of each stage — Style / Layout / Paint / Raster / Composite.</li><li><strong>Runtime performance</strong>: JIT deoptimization, GC pauses, long-task splitting, and INP optimization.</li><li><strong>Core metrics</strong>: Breakdown and optimization directions for LCP / INP / CLS / TTFB.</li><li><strong>Engineering practice</strong>: DevTools performance analysis, compositing-layer management, virtual lists, and scroll optimization.</li></ul><h2 id="article-guide" tabindex="-1">Article Guide <a class="header-anchor" href="#article-guide" aria-label="Permalink to &quot;Article Guide&quot;">​</a></h2><ul><li><a href="/en/performance/rendering-pitfalls">Rendering Performance Pitfalls</a> — Common traps and solutions at Layout / Paint / Composite stages.</li><li><a href="/en/performance/critical-path">The Critical Path of Modern Frontend Performance</a> — A complete performance model from TTFB to Hydration.</li></ul><h2 id="intended-readers" tabindex="-1">Intended Readers <a class="header-anchor" href="#intended-readers" aria-label="Permalink to &quot;Intended Readers&quot;">​</a></h2><ul><li>Performance owners who need to build a team-level performance diagnosis and optimization framework.</li><li>Intermediate and senior frontend engineers who want to move beyond single-point optimizations like &quot;add will-change.&quot;</li><li>Frontend architects who need to evaluate how technical choices affect the critical path.</li></ul>',11)])])}const h=i(t,[["render",r]]);export{g as __pageData,h as default};
